import 'package:flutter/material.dart'; import '../../domain/entities/report.dart'; import 'report_reason_tile.dart'; class ReportReasonSelector extends StatelessWidget{final ReportReason selectedReason; final ValueChanged<ReportReason> onChanged; const ReportReasonSelector({super.key,required this.selectedReason,required this.onChanged}); @override Widget build(BuildContext context)=>Column(children:ReportReason.values.map((r)=>ReportReasonTile(reason:r,selected:selectedReason==r,onTap:()=>onChanged(r))).toList());}
